def run():
    import os
    folder = 'email_drafts'
    if not os.path.exists(folder):
        return {'error': 'Dossier email_drafts introuvable — lancez d\'abord email_draft.', 'approved': [], 'file': ''}
    files = sorted([f for f in os.listdir(folder) if f.startswith('brouillons_') and f.endswith('.txt')])
    if not files:
        return {'error': 'Aucun fichier de brouillons dans email_drafts/ — lancez d\'abord email_draft.', 'approved': [], 'file': ''}
    latest = os.path.join(folder, files[-1])
    with open(latest, 'r', encoding='utf-8') as f:
        content = f.read()
    approved = []
    blocks = content.split('--- BROUILLON ')[1:]
    for block in blocks:
        data = {'to': '', 'subject': '', 'body': '', 'approved': False}
        in_body = False
        body_lines = []
        for line in block.strip().split('\n'):
            if line.startswith('TO: '):
                data['to'] = line[4:].strip()
            elif line.startswith('SUBJECT: '):
                data['subject'] = line[9:].strip()
            elif line.strip() == 'STATUS: APPROUVE':
                data['approved'] = True
            elif line.strip() == 'BODY:':
                in_body = True
            elif in_body and not line.startswith('---'):
                body_lines.append(line)
        data['body'] = '\n'.join(body_lines).strip()
        if data['approved'] and data['to'] and data['body']:
            approved.append({'to': data['to'], 'subject': data['subject'], 'body': data['body']})
    return {'file': latest, 'approved': approved}

def run(brouillons):
    import smtplib, os
    from email.mime.text import MIMEText
    if isinstance(brouillons, dict) and brouillons.get('error'):
        return 'Erreur : ' + brouillons['error']
    approved = brouillons.get('approved', []) if isinstance(brouillons, dict) else []
    fname    = brouillons.get('file', 'email_drafts/') if isinstance(brouillons, dict) else ''
    if not approved:
        return 'Aucune reponse approuvee.\nOuvrez ' + fname + ' et changez EN_ATTENTE en APPROUVE, puis relancez.'
    user = os.getenv('GMAIL_USER', '')
    pwd  = os.getenv('GMAIL_APP_PASSWORD', '')
    if not user or not pwd:
        return 'Credentials manquants — ajouter GMAIL_USER et GMAIL_APP_PASSWORD dans .env'
    sent, errors = [], []
    try:
        server = smtplib.SMTP_SSL('smtp.gmail.com', 465)
        server.login(user, pwd)
        for mail in approved:
            try:
                msg = MIMEText(mail['body'], 'plain', 'utf-8')
                msg['From']    = user
                msg['To']      = mail['to']
                msg['Subject'] = mail['subject']
                server.sendmail(user, mail['to'], msg.as_string())
                sent.append(mail['to'])
            except Exception as e:
                errors.append(mail['to'] + ' : ' + str(e))
        server.quit()
    except Exception as e:
        return 'Erreur SMTP : ' + str(e)
    result = str(len(sent)) + ' mail(s) envoye(s)'
    if sent:
        result += '\n' + '\n'.join('  -> ' + s for s in sent)
    if errors:
        result += '\n\nErreurs :\n' + '\n'.join('  ' + e for e in errors)
    return result
